// 获取年份对应的历史时期（通过插值）
export function findPeriod(year: number): HistoricalPeriod {
  const periods = historicalPeriods;
  
  // 找到最近的两个区间
  let closest = periods[0];
  let minDiff = Math.abs(year - closest.year);
  
  for (const period of periods) {
    const diff = Math.abs(year - period.year);
    if (diff < minDiff) {
      minDiff = diff;
      closest = period;
    }
  }
  
  return closest;
}

export const timelineYears = historicalPeriods.map(p => p.year);